    {
        // No palette available — return input as-is
        return input.Clone();
    }

    switch (ditherMode)
    {
        case "none":
            MapNoDither(input, output, palette, distanceMode, preserveAlpha);
            break;
        case "bayer4x4":
            MapBayerDither(input, output, palette, distanceMode, preserveAlpha);
            break;
        case "floydSteinberg":
            MapErrorDiffusion(input, output, palette, distanceMode, preserveAlpha);
            break;
    }

    return output;

private static List<(float R, float G, float B, float A)> ExtractPalette(PixelBuffer? paletteInput, bool preserveAlpha)
{
    var palette = new List<(float R, float G, float B, float A)>();

    if (paletteInput == null) return palette;

    var seen = new HashSet<long>();
    for (var y = 0; y < paletteInput.Height; y++)
    {
        for (var x = 0; x < paletteInput.Width; x++)
        {
            var (r, g, b, a) = paletteInput.GetPixel(x, y);

            // Skip fully transparent pixels in alpha-aware mode
            if (preserveAlpha && a < 0.01f) continue;

            // Deduplicate using quantized hash
            var hash = ((long)(r * 31) << 24) | ((long)(g * 31) << 16) | ((long)(b * 31) << 8) | (long)(a * 31);
            if (seen.Add(hash))
            {
                palette.Add((r, g, b, preserveAlpha ? a : 1f));
            }
        }
    }

    return palette;
}

private static readonly byte[] Bayer4 = { 0, 8, 2, 10, 12, 4, 14, 6, 3, 11, 1, 9, 15, 7, 13, 5 };

private static void MapNoDither(PixelBuffer input, PixelBuffer output, List<(float R, float G, float B, float A)> palette, string distanceMode, bool preserveAlpha)
{
    var size = input.Width;
    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);
        var nearest = FindNearest(r, g, b, preserveAlpha ? a : 1f, palette, distanceMode);
        output.SetPixel(x, y, nearest.R, nearest.G, nearest.B, preserveAlpha ? a : 1f);
    });
}

private static void MapBayerDither(PixelBuffer input, PixelBuffer output, List<(float R, float G, float B, float A)> palette, string distanceMode, bool preserveAlpha)
{
    var size = input.Width;
    output.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = input.GetPixel(x, y);
        var mx = x % 4;
        var my = y % 4;
        var threshold = Bayer4[my * 4 + mx];

        // Add dither offset to channels before nearest-color lookup
        var dr = r + threshold * 0.04f;
        var dg = g + threshold * 0.04f;
        var db = b + threshold * 0.04f;

        var nearest = FindNearest(
            Math.Clamp(dr, 0f, 1f),
            Math.Clamp(dg, 0f, 1f),
            Math.Clamp(db, 0f, 1f),
            preserveAlpha ? a : 1f,
            palette, distanceMode);
        output.SetPixel(x, y, nearest.R, nearest.G, nearest.B, preserveAlpha ? a : 1f);
    });
}

private static void MapErrorDiffusion(PixelBuffer input, PixelBuffer output, List<(float R, float G, float B, float A)> palette, string distanceMode, bool preserveAlpha)
{
    var w = input.Width;
    var h = input.Height;

    // Copy input to float array for in-place error diffusion
    var pixels = new float[w * h * 4];
    input.AsReadOnlySpan().CopyTo(pixels);

    for (var y = 0; y < h; y++)
    {
        for (var x = 0; x < w; x++)
        {
            var idx = (y * w + x) * 4;
            var r = pixels[idx];
            var g = pixels[idx + 1];
            var b = pixels[idx + 2];
            var a = pixels[idx + 3];

            var nearest = FindNearest(r, g, b, preserveAlpha ? a : 1f, palette, distanceMode);

            pixels[idx] = nearest.R;
            pixels[idx + 1] = nearest.G;
            pixels[idx + 2] = nearest.B;
            // Alpha unchanged

            var errR = r - nearest.R;
            var errG = g - nearest.G;
            var errB = b - nearest.B;

            // Floyd-Steinberg: 7/16 right, 3/16 bottom-left, 5/16 bottom, 1/16 bottom-right
            Diffuse(pixels, w, h, x + 1, y, errR * 7f / 16f, errG * 7f / 16f, errB * 7f / 16f);
            Diffuse(pixels, w, h, x - 1, y + 1, errR * 3f / 16f, errG * 3f / 16f, errB * 3f / 16f);
            Diffuse(pixels, w, h, x, y + 1, errR * 5f / 16f, errG * 5f / 16f, errB * 5f / 16f);
            Diffuse(pixels, w, h, x + 1, y + 1, errR * 1f / 16f, errG * 1f / 16f, errB * 1f / 16f);
        }
    }

    // Copy result to output
    for (var y = 0; y < h; y++)
    {
        for (var x = 0; x < w; x++)
        {
            var idx = (y * w + x) * 4;
            output.SetPixel(x, y, pixels[idx], pixels[idx + 1], pixels[idx + 2],
                preserveAlpha ? pixels[idx + 3] : 1f);
        }
    }
}

private static void Diffuse(float[] pixels, int w, int h, int x, int y, float er, float eg, float eb)
{
    if (x < 0 || x >= w || y < 0 || y >= h) return;
    var idx = (y * w + x) * 4;
    pixels[idx] = Math.Clamp(pixels[idx] + er, 0f, 1f);
    pixels[idx + 1] = Math.Clamp(pixels[idx + 1] + eg, 0f, 1f);
    pixels[idx + 2] = Math.Clamp(pixels[idx + 2] + eb, 0f, 1f);
}

private static (float R, float G, float B, float A) FindNearest(float r, float g, float b, float a,
    List<(float R, float G, float B, float A)> palette, string distanceMode)
{
    var best = palette[0];
    var bestDist = float.MaxValue;

    foreach (var color in palette)
    {
        var dist = distanceMode switch
        {
            "RGB" => ColorDistanceRgb(r, g, b, color.R, color.G, color.B),
            "HSV" => ColorDistanceHsvWeighted(r, g, b, color.R, color.G, color.B),
            _ => ColorDistancePerceptual(r, g, b, color.R, color.G, color.B)
        };

        if (dist < bestDist)
        {
            bestDist = dist;
            best = color;
        }
    }

    return best;
}

private static float ColorDistanceRgb(float r1, float g1, float b1, float r2, float g2, float b2)
{
    var dr = r1 - r2;
    var dg = g1 - g2;
    var db = b1 - b2;
    return dr * dr + dg * dg + db * db;
}

private static float ColorDistancePerceptual(float r1, float g1, float b1, float r2, float g2, float b2)
{
    // Weighted RGB: human vision is more sensitive to green
    var dr = r1 - r2;
    var dg = g1 - g2;
    var db = b1 - b2;
    return 0.299f * dr * dr + 0.587f * dg * dg + 0.114f * db * db;
}

private static float ColorDistanceHsvWeighted(float r1, float g1, float b1, float r2, float g2, float b2)
{
    // Convert both to HSV and compute weighted distance
    var (h1, s1, v1) = RgbToHsv(r1, g1, b1);
    var (h2, s2, v2) = RgbToHsv(r2, g2, b2);

    var dh = Math.Min(Math.Abs(h1 - h2), 1f - Math.Abs(h1 - h2));
    var ds = s1 - s2;
    var dv = v1 - v2;

    // Hue weighted more strongly — it's the most perceptually salient dimension
    return dh * dh * 3f + ds * ds * 1.5f + dv * dv;
}

private static (float H, float S, float V) RgbToHsv(float r, float g, float b)
{
    var max = Math.Max(r, Math.Max(g, b));
    var min = Math.Min(r, Math.Min(g, b));
    var delta = max - min;

    float h = 0;
    if (delta > 0.0001f)
    {
        if (max == r)
            h = ((g - b) / delta) % 6f;
        else if (max == g)
            h = (b - r) / delta + 2f;
        else
            h = (r - g) / delta + 4f;

        h /= 6f;
        if (h < 0) h += 1f;
    }

    var s = max > 0.0001f ? delta / max : 0f;
    return (h, s, max);
    }
}
